## 1. Safe Memory Operations (No-Alloc String Handling)

```asm
; ==============================================================================
; RawrXD Robust Memory Tools
; Zero-allocation string/memory primitives for GGUF parsing
; ==============================================================================

OPTION CASEMAP:NONE
OPTION WIN64:3

include \masm64\include64\kernel32.inc
includelib \masm64\lib64\kernel64.lib

; ------------------------------------------------------------------------------
; StrSafe_SkipChunk: Seeks past oversized data without heap allocation
; RCX = hFile (HANDLE)
; RDX = Length to skip (uint64)
; Returns: RAX = 1 (success), 0 (failure), LastError preserved
; Clobbers: R8-R11
; ------------------------------------------------------------------------------
StrSafe_SkipChunk PROC FRAME hFile:QWORD, cbLength:QWORD
    LOCAL liDistance: LARGE_INTEGER
    LOCAL dwPtrLow: DWORD
    LOCAL dwPtrHigh: DWORD
    
    mov rax, cbLength
    mov [liDistance.QuadPart], rax
    
    ; Method 1: SetFilePointerEx (preferred for 64-bit)
    Invoke SetFilePointerEx, hFile, liDistance, NULL, FILE_CURRENT
    test rax, rax
    jz @@fallback_seek
    
    mov rax, 1
    ret
    
@@fallback_seek:
    ; Method 2: Manual looping for exotic filesystems
    mov r8, cbLength
    mov r10, hFile
    
@@seek_loop:
    test r8, r8
    jz @@success
    
    ; Skip in 1GB chunks to avoid SetFilePointerEx limits on 32-bit builds
    mov r9, 40000000h  ; 1GB
    cmp r8, r9
    cmovb r9, r8       ; r9 = min(remaining, 1GB)
    
    mov [liDistance.QuadPart], r9
    Invoke SetFilePointerEx, r10, liDistance, NULL, FILE_CURRENT
    test rax, rax
    jz @@fail
    
    sub r8, r9
    jmp @@seek_loop
    
@@success:
    mov rax, 1
    ret
    
@@fail:
    xor rax, rax
    ret
StrSafe_SkipChunk ENDP

; ------------------------------------------------------------------------------
; MemSafe_PeekU64: Reads uint64_t without buffer allocation
; RCX = hFile
; RDX = pointer to uint64_t result
; Returns: RAX = bytes read (8) or 0
; ------------------------------------------------------------------------------
MemSafe_PeekU64 PROC FRAME hFile:QWORD, pResult:QWORD
    LOCAL dwRead: DWORD
    LOCAL qwordBuf: QWORD
    
    Invoke ReadFile, hFile, ADDR qwordBuf, 8, ADDR dwRead, NULL
    
    cmp dwRead, 8
    jne @@fail
    
    mov rax, pResult
    mov rdx, qwordBuf
    mov [rax], rdx
    
    mov rax, 8
    ret
    
@@fail:
    xor rax, rax
    ret
MemSafe_PeekU64 ENDP
