## 2. Robust Buffered File I/O (Streaming)

```asm
; ==============================================================================
; RawrXD Buffered Stream Reader
; Reverse-engineered from GGUF IO patterns - zero-copy streaming
; ==============================================================================

GGUF_STREAM_BUFFERSIZE EQU 65536  ; 64KB ring buffer

GGUF_STREAM_CTX STRUCT
    hFile       QWORD ?           ; HANDLE
    pBuffer     QWORD ?           ; VirtualAlloc'd buffer
    cbBuffer    QWORD ?           ; GGUF_STREAM_BUFFERSIZE
    cbValid     QWORD ?           ; Valid bytes in buffer
    cbConsumed  QWORD ?           ; Bytes already consumed from buffer
    fileOffset  QWORD ?           ; Current 64-bit file position
    fEOF        BYTE ?            ; EOF flag
    fError      BYTE ?            ; Error flag
    padding     WORD ?
GGUF_STREAM_CTX ENDS

; ------------------------------------------------------------------------------
; GGUF_StreamInit: Initialize buffered reader
; RCX = hFile (must be opened FILE_FLAG_SEQUENTIAL_SCAN)
; RDX = pointer to GGUF_STREAM_CTX (uninitialized)
; Returns: RAX = 1 success, 0 fail
; ------------------------------------------------------------------------------
GGUF_StreamInit PROC FRAME hFile:QWORD, pCtx:QWORD
    mov rbx, pCtx
    mov [rbx].GGUF_STREAM_CTX.hFile, rcx
    mov [rbx].GGUF_STREAM_CTX.cbValid, 0
    mov [rbx].GGUF_STREAM_CTX.cbConsumed, 0
    mov [rbx].GGUF_STREAM_CTX.fEOF, 0
    mov [rbx].GGUF_STREAM_CTX.fError, 0
    
    ; Allocate ring buffer with guard page
    Invoke VirtualAlloc, NULL, GGUF_STREAM_BUFFERSIZE + 4096, \
           MEM_COMMIT or MEM_RESERVE, PAGE_READWRITE
    test rax, rax
    jz @@fail
    
    mov [rbx].GGUF_STREAM_CTX.pBuffer, rax
    mov [rbx].GGUF_STREAM_CTX.cbBuffer, GGUF_STREAM_BUFFERSIZE
    
    ; Get current file position
    Invoke SetFilePointer, hFile, 0, NULL, FILE_CURRENT
    cmp rax, INVALID_SET_FILE_POINTER
    je @@cleanup_fail
    
    mov [rbx].GGUF_STREAM_CTX.fileOffset, rax
    
    mov rax, 1
    ret
    
@@cleanup_fail:
    Invoke VirtualFree, [rbx].GGUF_STREAM_CTX.pBuffer, 0, MEM_RELEASE
@@fail:
    xor rax, rax
    ret
GGUF_StreamInit ENDP

; ------------------------------------------------------------------------------
; GGUF_StreamFill: Refill buffer from disk (JIT prefetching)
; RCX = pCtx
; Returns: RAX = valid bytes available, 0 = EOF/error
; ------------------------------------------------------------------------------
GGUF_StreamFill PROC FRAME pCtx:QWORD
    mov rbx, pCtx
    mov rdi, [rbx].GGUF_STREAM_CTX.pBuffer
    mov r12, [rbx].GGUF_STREAM_CTX.hFile
    
    ; Shift unconsumed data to front (overlapped I/O prep)
    mov rcx, [rbx].GGUF_STREAM_CTX.cbValid
    sub rcx, [rbx].GGUF_STREAM_CTX.cbConsumed
    jz @@read_fresh
    
    ; memmove remaining data to start of buffer
    mov rsi, rdi
    add rsi, [rbx].GGUF_STREAM_CTX.cbConsumed
    xchg rcx, [rbx].GGUF_STREAM_CTX.cbValid
    rep movsb
    
    mov [rbx].GGUF_STREAM_CTX.cbConsumed, 0
    
@@read_fresh:
    ; Calculate space remaining
    mov rcx, GGUF_STREAM_BUFFERSIZE
    sub rcx, [rbx].GGUF_STREAM_CTX.cbValid
    
    ; Read into buffer tail
    lea rdx, [rdi + rbx.GGUF_STREAM_CTX.cbValid]
    Invoke ReadFile, r12, rdx, ecx, ADDR [rbx].GGUF_STREAM_CTX.dwLastRead, NULL
    
    test rax, rax
    jz @@io_error
    
    mov eax, [rbx].GGUF_STREAM_CTX.dwLastRead
    test eax, eax
    jz @@eof
    
    add [rbx].GGUF_STREAM_CTX.cbValid, rax
    mov rax, [rbx].GGUF_STREAM_CTX.cbValid
    ret
    
@@eof:
    mov [rbx].GGUF_STREAM_CTX.fEOF, 1
@@io_error:
    mov [rbx].GGUF_STREAM_CTX.fError, 1
    xor rax, rax
    ret
GGUF_StreamFill ENDP
