; Returns: RAX = valid bytes available, 0 = EOF/error
; ------------------------------------------------------------------------------
GGUF_StreamFill PROC FRAME pCtx:QWORD
    mov rbx, pCtx
    mov rdi, [rbx].GGUF_STREAM_CTX.pBuffer
    mov r12, [rbx].GGUF_STREAM_CTX.hFile
    
    ; Shift unconsumed data to front (overlapped I/O prep)
    mov rcx, [rbx].GGUF_STREAM_CTX.cbValid
    sub rcx, [rbx].GGUF_STREAM_CTX.cbConsumed
    jz @@read_fresh
    
    ; memmove remaining data to start of buffer
    mov rsi, rdi
    add rsi, [rbx].GGUF_STREAM_CTX.cbConsumed
    xchg rcx, [rbx].GGUF_STREAM_CTX.cbValid
    rep movsb
    
    mov [rbx].GGUF_STREAM_CTX.cbConsumed, 0
    
@@read_fresh:
    ; Calculate space remaining
    mov rcx, GGUF_STREAM_BUFFERSIZE
    sub rcx, [rbx].GGUF_STREAM_CTX.cbValid
    
    ; Read into buffer tail
    lea rdx, [rdi + rbx.GGUF_STREAM_CTX.cbValid]
    Invoke ReadFile, r12, rdx, ecx, ADDR [rbx].GGUF_STREAM_CTX.dwLastRead, NULL
    
    test rax, rax
    jz @@io_error
    
    mov eax, [rbx].GGUF_STREAM_CTX.dwLastRead
    test eax, eax
    jz @@eof
    
    add [rbx].GGUF_STREAM_CTX.cbValid, rax
    mov rax, [rbx].GGUF_STREAM_CTX.cbValid
    ret
    
@@eof:
    mov [rbx].GGUF_STREAM_CTX.fEOF, 1
@@io_error:
    mov [rbx].GGUF_STREAM_CTX.fError, 1
    xor rax, rax
    ret
GGUF_StreamFill ENDP
```

## 3. GGUF-Specific Robust Parser (Zero-Alloc Metadata Skip)

```asm
; ==============================================================================
; GGUF Robust Metadata Parser
; Handles corrupted/oversized values without bad_alloc
; ==============================================================================

GGUF_MAX_STRING_LENGTH EQU 01000000h  ; 16MB hard limit
GGUF_MAGIC EQU 46554747h              ; "GGUF" little-endian

; ------------------------------------------------------------------------------
; GGUF_SkipStringValue: Robust skip for corrupted string lengths
; RCX = hFile
; Returns: RAX = 1 success, 0 fail
; Side effect: File pointer advanced past string payload
; ------------------------------------------------------------------------------
GGUF_SkipStringValue PROC FRAME hFile:QWORD
    LOCAL strLen: QWORD
    
    ; Read length (uint64_le)
    Invoke MemSafe_PeekU64, hFile, ADDR strLen
    test rax, rax
    jz @@fail
    
    ; Sanity check: Max 16MB strings (catches corruption)
    cmp strLen, GGUF_MAX_STRING_LENGTH
    ja @@corrupted_length
    
    ; Skip payload
    Invoke StrSafe_SkipChunk, hFile, strLen
    test rax, rax
    jz @@fail
    
    ret
    
@@corrupted_length:
    ; Log corruption attempt but don't crash
    ; SetLastError(ERROR_INVALID_DATA)
    Invoke SetLastError, 0000000Dh  ; ERROR_INVALID_DATA
@@fail:
    xor rax, rax
    ret
GGUF_SkipStringValue ENDP

; ------------------------------------------------------------------------------
; GGUF_SkipArrayValue: Skip GGUF arrays (type + count + data)
; RCX = hFile
; RDX = ElementType (byte)
; Returns: RAX = 1 success
; ------------------------------------------------------------------------------
GGUF_SkipArrayValue PROC FRAME hFile:QWORD, elemType:BYTE
    LOCAL elemCount: QWORD
    LOCAL elemSize: QWORD
    LOCAL totalBytes: QWORD
    
    ; Read element count
    Invoke MemSafe_PeekU64, hFile, ADDR elemCount
    test rax, rax
    jz @@fail
    
    ; Calculate element size from type
    xor rcx, rcx
    mov cl, elemType
    mov rax, 1      ; GGUF_TYPE_UINT8, INT8
    
    cmp cl, 2       ; GGUF_TYPE_UINT16, INT16
    je @@size2
    cmp cl, 4       ; GGUF_TYPE_UINT32, INT32
    je @@size4
    cmp cl, 5       ; GGUF_TYPE_FLOAT32
    je @@size4
    cmp cl, 6       ; GGUF_TYPE_BOOL (1 byte)
    je @@size1
    cmp cl, 7       ; GGUF_TYPE_STRING (handled specially)
    je @@string_array
    cmp cl, 8       ; GGUF_TYPE_ARRAY (nested!)
    je @@nested_array
    cmp cl, 9       ; GGUF_TYPE_UINT64, INT64
    je @@size8
    cmp cl, 10      ; GGUF_TYPE_FLOAT64
    je @@size8
    
    jmp @@unknown_type  ; Type 11+ or corrupted
    
@@size1: jmp @@calc_total
@@size2:
    mov rax, 2
    jmp @@calc_total
@@size4:
    mov rax, 4
    jmp @@calc_total
@@size8:
    mov rax, 8
    jmp @@calc_total
    
@@string_array:
    ; String arrays = array of (uint64 length + data)
    ; Must iterate and skip each string
    mov r8, elemCount
    test r8, r8
    jz @@done
    
@@string_loop:
    Invoke GGUF_SkipStringValue, hFile
    test rax, rax
    jz @@fail
    dec r8
    jnz @@string_loop
    jmp @@done
    
@@nested_array:
    ; Nested arrays - recursive skip (marked as risky)
    mov r8, elemCount
@@nested_loop:
    Invoke GGUF_SkipArrayValue, hFile, 0  ; Unknown inner type - dangerous
    test rax, rax
    jz @@fail
    dec r8
    jnz @@nested_loop
    jmp @@done
    
@@calc_total:
    mov elemSize, rax
    mov rax, elemCount
    mul elemSize  ; RAX = total bytes
    jc @@overflow  ; Multiply overflow = corruption
    
    Invoke StrSafe_SkipChunk, hFile, rax
    test rax, rax
    jz @@fail
    
@@done:
    mov rax, 1
    ret
    
@@unknown_type:
    Invoke SetLastError, 00000057h  ; ERROR_INVALID_PARAMETER
@@overflow:
@@fail:
    xor rax, rax
    ret
GGUF_SkipArrayValue ENDP
```

