    bool SkipUnsafeString(const char* keyName) {
        uint64_t len = 0;
        DWORD read = 0;
        
        // Peek length first (no allocation)
        if (!ReadFile(hFile_, &len, 8, &read, NULL) || read != 8)
            return false;
            
        if (len > 0xFFFFFF) {  // 16MB limit
            // Corrupted or massive - skip without reading
            SetFilePointerEx(hFile_, *(LARGE_INTEGER*)&len, NULL, FILE_CURRENT);
            return true;
        }
        
        // Small enough - seek back and let normal path handle it
        LARGE_INTEGER neg = {0};
        neg.QuadPart = -8;
        SetFilePointerEx(hFile_, neg, NULL, FILE_CURRENT);
        return false;  // Signal caller to read normally
    }
};
